<?php
/** Fuel transaction detail. */
declare(strict_types=1);require_once __DIR__.'/../../config/config.php';requireAuth();enforceModuleAccess('fuel');$s=getDb()->prepare('SELECT f.*,v.registration_number,t.trip_number FROM fuel_logs f JOIN vehicles v ON v.id=f.vehicle_id LEFT JOIN trips t ON t.id=f.trip_id WHERE f.id=?');$s->execute([(int)($_GET['id']??0)]);$f=$s->fetch();if(!$f){setFlash('danger','Fuel log not found.');redirect('modules/fuel/index.php');}$pageTitle='Fuel log';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';?><main class="main-content fuel-module"><?php require ROOT_PATH.'/includes/navbar.php';?><article class="card dashboard-card"><h1 class="page-title"><?=e($f['fuel_code']?:'Fuel log #'.$f['id'])?></h1><dl class="profile-list"><dt>Vehicle</dt><dd><?=e($f['registration_number'])?></dd><dt>Trip</dt><dd><?=e($f['trip_number']?:'—')?></dd><dt>Fuel</dt><dd><?=e($f['quantity_liters'].' L '.$f['fuel_type'])?></dd><dt>Total</dt><dd><?=e(formatCurrency((float)$f['cost']))?></dd><dt>Filled</dt><dd><?=e(formatDate($f['logged_date']))?></dd></dl></article></main><?php require ROOT_PATH.'/includes/footer.php';?>
